import { environment } from '../../../../environments/environment';
import { Component, OnInit, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterModule } from '@angular/router';
import { HttpClient } from '@angular/common/http';
import { AlumnoService } from '../../../core/services/alumno.service';
import { CursoService } from '../../../core/services/curso.service';
import { AuthService } from '../../../core/services/auth.service';
import { AlumnoDashboardService } from '../../../core/services/alumno-dashboard.service';
import { CertificadoService } from '../../../core/services/certificado.service';
import { AuditoriaService } from '../../../core/services/auditoria.service';
import { PagoService } from '../../../core/services/pago.service';
import { UserProfile } from '../../../core/models/user-profile.model';

@Component({
  selector: 'app-dashboard-home',
  standalone: true,
  imports: [CommonModule, RouterModule],
  templateUrl: './dashboard-home.component.html',
  styleUrls: ['./dashboard-home.component.css']
})
export class DashboardHomeComponent implements OnInit {
  private authService = inject(AuthService);
  private alumnoService = inject(AlumnoService);
  private cursoService = inject(CursoService);
  private studentService = inject(AlumnoDashboardService);
  private certificadoService = inject(CertificadoService);
  private auditoriaService = inject(AuditoriaService);
  private pagoService = inject(PagoService);
  private http = inject(HttpClient);

  profile: UserProfile | null = null;
  isLoading = true;

  // Admin stats
  totalAlumnos = 0;
  totalCursos = 0;
  totalCertificados = 0;
  systemStatus: any = null;
  recentLogins: any[] = [];
  pendingPayments: any[] = [];
  coursesList: any[] = [];
  recentEvents: any[] = [];
  planStats: any[] = [];

  // Student stats
  studentCursosInscritos = 0;
  studentCursosCompletados = 0;
  studentCertificados = 0;
  studentCursos: any[] = [];

  ngOnInit(): void {
    this.authService.getProfile().subscribe({
      next: (user) => {
        this.profile = user;
        if (user.rol === 'ADMINISTRADOR') {
          this.loadAdminStats();
        } else {
          this.loadStudentStats();
        }
      },
      error: (err) => {
        console.error('Error fetching profile:', err);
        this.isLoading = false;
      }
    });
  }

  loadAdminStats(): void {
    this.isLoading = true;

    // Load Alumnos
    this.alumnoService.listarAlumnos().subscribe({
      next: (alumnos) => {
        const total = alumnos.length;
        this.totalAlumnos = total;

        // Count subscriptions
        const counts = { BASICO: 0, INTERMEDIO: 0, PREMIUM: 0 };
        alumnos.forEach(alumno => {
          const sub = alumno.nivelSuscripcion || 'BASICO';
          if (sub in counts) {
            counts[sub as keyof typeof counts]++;
          } else {
            (counts as any)[sub] = ((counts as any)[sub] || 0) + 1;
          }
        });

        this.planStats = [
          { 
            name: 'BASICO', 
            count: counts.BASICO, 
            percentage: total > 0 ? Math.round((counts.BASICO / total) * 100) : 0,
            cssClass: 'bg-slate-50 text-slate-700 border border-slate-200', 
            barClass: 'bg-slate-400',
            icon: 'person' 
          },
          { 
            name: 'INTERMEDIO', 
            count: counts.INTERMEDIO, 
            percentage: total > 0 ? Math.round((counts.INTERMEDIO / total) * 100) : 0,
            cssClass: 'bg-blue-50 text-blue-700 border border-blue-200', 
            barClass: 'bg-blue-500',
            icon: 'school' 
          },
          { 
            name: 'PREMIUM', 
            count: counts.PREMIUM, 
            percentage: total > 0 ? Math.round((counts.PREMIUM / total) * 100) : 0,
            cssClass: 'bg-amber-50 text-amber-800 border border-amber-200', 
            barClass: 'bg-amber-500',
            icon: 'workspace_premium' 
          }
        ];
      }
    });

    // Load Cursos
    this.cursoService.listarCursos().subscribe({
      next: (cursos) => {
        this.totalCursos = cursos.length;
        this.coursesList = (cursos || []).slice(0, 5); // top 5 courses to display
      }
    });

    // Load Certificados
    this.certificadoService.listarCertificados().subscribe({
      next: (certs) => {
        this.totalCertificados = certs.length;
      }
    });

    // Load System status
    this.http.get<any>(environment.apiUrl + '/sistema/status').subscribe({
      next: (status) => {
        this.systemStatus = status;
      }
    });

    // Load Pending Payments
    this.pagoService.listarPagosPendientes().subscribe({
      next: (pagos) => {
        this.pendingPayments = pagos || [];
      }
    });

    // Load System events
    this.auditoriaService.getEventosSistema().subscribe({
      next: (events) => {
        this.recentEvents = (events || []).slice(0, 5);
      }
    });

    // Load Login audits
    this.auditoriaService.getLoginAuditoria().subscribe({
      next: (logins) => {
        this.recentLogins = (logins || []).slice(0, 5);
        this.isLoading = false;
      },
      error: (err) => {
        console.error('Error loading audits:', err);
        this.isLoading = false;
      }
    });
  }

  aprobarPago(id: number): void {
    if (confirm('¿Confirmas la verificación del depósito y la activación de la suscripción del alumno?')) {
      this.pagoService.aprobarPago(id).subscribe({
        next: (res) => {
          alert(res.mensaje || 'Pago verificado y suscripción actualizada con éxito.');
          this.loadAdminStats();
        },
        error: (err) => {
          console.error('Error approving payment:', err);
          alert(err.error?.error || 'No se pudo aprobar el pago.');
        }
      });
    }
  }

  loadStudentStats(): void {
    this.isLoading = true;
    this.studentService.getMetrics().subscribe({
      next: (metrics) => {
        this.studentCursosInscritos = metrics.cursosInscritos;
        this.studentCursosCompletados = metrics.cursosCompletados;
        this.studentCertificados = metrics.certificados;
        
        // Fetch enrolled courses for display on home dashboard
        this.studentService.getEnrolledCursos().subscribe({
          next: (cursos) => {
            this.studentCursos = (cursos || []).slice(0, 3); // top 3 courses
            this.isLoading = false;
          },
          error: (err) => {
            console.error('Error loading enrolled courses:', err);
            this.isLoading = false;
          }
        });
      },
      error: (err) => {
        console.error('Error loading student metrics:', err);
        this.isLoading = false;
      }
    });
  }
}
<div class="space-y-6 font-body" *ngIf="profile">

  <!-- Loading State -->
  <div *ngIf="isLoading" class="flex flex-col items-center justify-center p-12 sm:p-20 border border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900 transition-colors duration-300">
    <span class="animate-spin inline-block w-8 h-8 border-4 border-primary border-t-transparent rounded-full mb-3"></span>
    <span class="text-xs font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest">Cargando métricas...</span>
  </div>

  <div *ngIf="!isLoading">
    <!-- ================= ADMINISTRATOR VIEW ================= -->
    <ng-container *ngIf="profile.rol === 'ADMINISTRADOR'">
      <!-- Premium Welcome Banner -->
      <div class="welcome-banner relative overflow-hidden bg-gradient-to-r from-slate-950 via-[#0d1527] to-slate-950 border border-slate-800 p-5 sm:p-8 rounded-none shadow-[6px_6px_0px_0px_rgba(99,102,241,0.1)] text-white">
        <!-- Abstract light graphic -->
        <div class="absolute -right-16 -top-16 w-48 h-48 bg-indigo-500/10 rounded-full blur-3xl pointer-events-none"></div>
        <div class="absolute -left-16 -bottom-16 w-48 h-48 bg-blue-500/10 rounded-full blur-3xl pointer-events-none"></div>

        <div class="flex flex-col md:flex-row md:items-center justify-between gap-4 relative z-10">
          <div class="flex items-center gap-3 sm:gap-4">
            <div class="w-12 h-12 sm:w-14 sm:h-14 bg-gradient-to-br from-indigo-500 to-blue-600 flex items-center justify-center rounded-none font-black text-xl sm:text-2xl shadow-[4px_4px_0px_0px_rgba(255,255,255,0.2)] shrink-0">
              A
            </div>
            <div>
              <span class="text-[9px] font-black tracking-widest text-indigo-400 uppercase">Consola de Control Central</span>
              <h1 class="text-lg sm:text-2xl font-black tracking-tight uppercase mt-0.5">Campus Virtual INSTEIP</h1>
              <p class="text-slate-400 text-[11px] sm:text-xs mt-1">Supervisión operativa, seguridad de accesos y estado de infraestructura.</p>
            </div>
          </div>
          <div class="flex items-center gap-2">
            <span class="w-2.5 h-2.5 bg-emerald-500 rounded-none animate-pulse"></span>
            <span class="text-[9px] font-black text-slate-300 uppercase tracking-widest bg-slate-900 border border-slate-800 px-3 py-1.5">
              Servidor Activo (8080)
            </span>
          </div>
        </div>
      </div>

      <!-- Accesos Rápidos (Acciones Rápidas) -->
      <div class="grid grid-cols-2 md:grid-cols-4 gap-3 sm:gap-4 mt-4 sm:mt-6">
        <a 
          routerLink="/dashboard/cursos" 
          class="action-card border border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900 p-3 sm:p-4 flex items-center gap-2 sm:gap-3.5 shadow-sm hover:shadow-md hover:-translate-y-0.5 transition-all duration-300 rounded-none group select-none">
          <div class="action-icon w-9 h-9 sm:w-10 sm:h-10 bg-slate-100 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 flex items-center justify-center text-slate-700 dark:text-slate-300 rounded-none shrink-0 group-hover:bg-primary group-hover:text-white transition-colors duration-300">
            <span class="material-symbols-outlined text-lg">add_box</span>
          </div>
          <div>
            <span class="text-[9px] font-bold text-slate-400 dark:text-slate-500 uppercase block tracking-wider leading-none">Gestión</span>
            <span class="text-xs font-black text-slate-800 dark:text-slate-200 uppercase tracking-tight leading-none">Cursos</span>
          </div>
        </a>

        <a 
          routerLink="/dashboard/alumnos" 
          class="action-card border border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900 p-3 sm:p-4 flex items-center gap-2 sm:gap-3.5 shadow-sm hover:shadow-md hover:-translate-y-0.5 transition-all duration-300 rounded-none group select-none">
          <div class="action-icon w-9 h-9 sm:w-10 sm:h-10 bg-slate-100 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 flex items-center justify-center text-slate-700 dark:text-slate-300 rounded-none shrink-0 group-hover:bg-primary group-hover:text-white transition-colors duration-300">
            <span class="material-symbols-outlined text-lg">person_add</span>
          </div>
          <div>
            <span class="text-[9px] font-bold text-slate-400 dark:text-slate-500 uppercase block tracking-wider leading-none">Alumnos</span>
            <span class="text-xs font-black text-slate-800 dark:text-slate-200 uppercase tracking-tight leading-none">Matricular</span>
          </div>
        </a>

        <a 
          routerLink="/dashboard/auditoria" 
          class="action-card border border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900 p-3 sm:p-4 flex items-center gap-2 sm:gap-3.5 shadow-sm hover:shadow-md hover:-translate-y-0.5 transition-all duration-300 rounded-none group select-none">
          <div class="action-icon w-9 h-9 sm:w-10 sm:h-10 bg-slate-100 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 flex items-center justify-center text-slate-700 dark:text-slate-300 rounded-none shrink-0 group-hover:bg-primary group-hover:text-white transition-colors duration-300">
            <span class="material-symbols-outlined text-lg">security</span>
          </div>
          <div>
            <span class="text-[9px] font-bold text-slate-400 dark:text-slate-500 uppercase block tracking-wider leading-none">Auditoría</span>
            <span class="text-xs font-black text-slate-800 dark:text-slate-200 uppercase tracking-tight leading-none">Seguridad</span>
          </div>
        </a>

        <a 
          routerLink="/dashboard/sistema" 
          class="action-card border border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900 p-3 sm:p-4 flex items-center gap-2 sm:gap-3.5 shadow-sm hover:shadow-md hover:-translate-y-0.5 transition-all duration-300 rounded-none group select-none">
          <div class="action-icon w-9 h-9 sm:w-10 sm:h-10 bg-slate-100 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 flex items-center justify-center text-slate-700 dark:text-slate-300 rounded-none shrink-0 group-hover:bg-primary group-hover:text-white transition-colors duration-300">
            <span class="material-symbols-outlined text-lg">settings_suggest</span>
          </div>
          <div>
            <span class="text-[9px] font-bold text-slate-400 dark:text-slate-500 uppercase block tracking-wider leading-none">Sistema</span>
            <span class="text-xs font-black text-slate-800 dark:text-slate-200 uppercase tracking-tight leading-none">Monitoreo</span>
          </div>
        </a>
      </div>

      <!-- Dashboard Metrics Grid -->
      <div class="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 gap-4 sm:gap-6 mt-4 sm:mt-6">
        <!-- Metric 1: Total Alumnos -->
        <div class="metric-card border border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900 p-4 sm:p-6 rounded-none shadow-sm hover:shadow-md hover:-translate-y-0.5 transition-all duration-300 flex items-center justify-between">
          <div>
            <span class="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest">Total Alumnos</span>
            <h3 class="metric-number text-3xl sm:text-4xl font-black text-slate-900 dark:text-white mt-2 tracking-tight">{{ totalAlumnos }}</h3>
            <p class="text-[10px] text-emerald-600 font-bold mt-1.5 flex items-center gap-1">
              <span class="w-1.5 h-1.5 bg-emerald-500 rounded-full"></span>
              Suscripciones Activas
            </p>
          </div>
          <div class="metric-icon w-12 h-12 sm:w-14 sm:h-14 border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 flex items-center justify-center text-slate-500 dark:text-slate-400 rounded-none shrink-0">
            <span class="material-symbols-outlined text-2xl sm:text-3xl">group</span>
          </div>
        </div>

        <!-- Metric 2: Total Cursos -->
        <div class="metric-card border border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900 p-4 sm:p-6 rounded-none shadow-sm hover:shadow-md hover:-translate-y-0.5 transition-all duration-300 flex items-center justify-between">
          <div>
            <span class="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest">Total Cursos</span>
            <h3 class="metric-number text-3xl sm:text-4xl font-black text-slate-900 dark:text-white mt-2 tracking-tight">{{ totalCursos }}</h3>
            <p class="text-[10px] text-slate-400 dark:text-slate-500 font-semibold mt-1.5">Módulos educativos</p>
          </div>
          <div class="metric-icon w-12 h-12 sm:w-14 sm:h-14 border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 flex items-center justify-center text-slate-500 dark:text-slate-400 rounded-none shrink-0">
            <span class="material-symbols-outlined text-2xl sm:text-3xl">menu_book</span>
          </div>
        </div>

        <!-- Metric 3: Total Certificados -->
        <div class="metric-card border border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900 p-4 sm:p-6 rounded-none shadow-sm hover:shadow-md hover:-translate-y-0.5 transition-all duration-300 flex items-center justify-between sm:col-span-2 md:col-span-1">
          <div>
            <span class="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest">Certificados Emitidos</span>
            <h3 class="text-3xl sm:text-4xl font-black text-slate-900 dark:text-white mt-2 tracking-tight">{{ totalCertificados }}</h3>
            <p class="text-[10px] text-slate-400 dark:text-slate-500 font-semibold mt-1.5">Validación Pública</p>
          </div>
          <div class="w-12 h-12 sm:w-14 sm:h-14 border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 flex items-center justify-center text-slate-400 dark:text-slate-500 rounded-none shrink-0">
            <span class="material-symbols-outlined text-2xl sm:text-3xl">workspace_premium</span>
          </div>
        </div>
      </div>

      <!-- Live Monitoring and Recent Activities Split Grid -->
      <div class="grid grid-cols-1 lg:grid-cols-2 gap-4 sm:gap-6 mt-4 sm:mt-6">

        <!-- Distribución de Planes Contratados -->
        <div class="border border-slate-200 dark:border-slate-800 p-4 sm:p-6 bg-white dark:bg-slate-900 rounded-none shadow-[4px_4px_0px_0px_rgba(15,23,42,0.05)] dark:shadow-[4px_4px_0px_0px_rgba(0,0,0,0.22)] transition-colors duration-300">
          <div class="flex items-center justify-between border-b border-slate-100 dark:border-slate-800 pb-3 mb-4">
            <h2 class="text-xs font-black text-slate-900 dark:text-slate-100 uppercase tracking-wider flex items-center gap-1.5 min-w-0">
              <span class="material-symbols-outlined text-base text-indigo-600 shrink-0">card_membership</span>
              <span class="truncate">Distribución de Planes</span>
            </h2>
            <span class="text-[9px] font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest bg-slate-100 dark:bg-slate-800 px-2 py-0.5 shrink-0 ml-2">
              {{ totalAlumnos }} Alumnos
            </span>
          </div>

          <!-- Plans List -->
          <div class="space-y-4">
            <div *ngFor="let plan of planStats" class="border border-slate-200 dark:border-slate-800 p-3 sm:p-4 bg-slate-50/50 dark:bg-slate-800/30 flex flex-col gap-3">
              <div class="flex items-center justify-between gap-2">
                <div class="flex items-center gap-2 sm:gap-3 min-w-0">
                  <div [class]="plan.cssClass + ' w-9 h-9 flex items-center justify-center rounded-none shrink-0'">
                    <span class="material-symbols-outlined text-base">{{ plan.icon }}</span>
                  </div>
                  <div class="min-w-0">
                    <span class="text-xs font-black text-slate-900 dark:text-slate-100 uppercase tracking-wide block truncate">{{ plan.name }}</span>
                    <span class="text-[9px] text-slate-400 dark:text-slate-500 block">Plan de Suscripción</span>
                  </div>
                </div>
                <div class="flex items-center gap-1 sm:gap-2 shrink-0">
                  <span class="text-xs font-black text-slate-900 dark:text-slate-100 font-mono bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-700 px-2 py-1">
                    {{ plan.count }}
                  </span>
                  <span class="text-[9px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-wider hidden sm:inline">usuarios ({{ plan.percentage }}%)</span>
                  <span class="text-[9px] font-bold text-slate-400 dark:text-slate-500 sm:hidden">{{ plan.percentage }}%</span>
                </div>
              </div>
              <!-- Percentage Bar -->
              <div class="w-full bg-slate-200 dark:bg-slate-800 h-1.5 rounded-none overflow-hidden">
                <div [class]="plan.barClass + ' h-full transition-all duration-500'" [style.width.%]="plan.percentage"></div>
              </div>
            </div>
          </div>
        </div>

        <!-- Recent Activity Logs Widget -->
        <div class="border border-slate-200 dark:border-slate-800 p-4 sm:p-6 bg-white dark:bg-slate-900 rounded-none shadow-[4px_4px_0px_0px_rgba(15,23,42,0.05)] dark:shadow-[4px_4px_0px_0px_rgba(0,0,0,0.22)] transition-colors duration-300">
          <div class="flex items-center justify-between border-b border-slate-100 dark:border-slate-800 pb-3 mb-4">
            <h2 class="text-xs font-black text-slate-900 dark:text-slate-100 uppercase tracking-wider flex items-center gap-1.5">
              <span class="material-symbols-outlined text-base text-indigo-600 shrink-0">admin_panel_settings</span>
              Accesos Recientes
            </h2>
            <a routerLink="/dashboard/auditoria" class="text-[9px] font-bold text-indigo-600 hover:text-indigo-800 dark:text-indigo-400 dark:hover:text-indigo-300 uppercase tracking-widest shrink-0 ml-2">
              Ver Todos
            </a>
          </div>

          <!-- Loader for Logins -->
          <div *ngIf="recentLogins.length === 0 && isLoading" class="flex flex-col items-center justify-center py-10 text-slate-400 dark:text-slate-500">
            <span class="animate-spin inline-block w-6 h-6 border-2 border-slate-300 dark:border-slate-700 border-t-transparent rounded-full mb-2"></span>
            <span class="text-[9px] font-bold uppercase tracking-widest">Cargando registros...</span>
          </div>

          <!-- Empty logs -->
          <div *ngIf="recentLogins.length === 0 && !isLoading" class="text-center py-10 text-slate-400 dark:text-slate-500">
            <span class="material-symbols-outlined text-3xl mb-1 text-slate-300 dark:text-slate-600">security_update_warning</span>
            <p class="text-xs">No hay registros de auditoría de accesos disponibles.</p>
          </div>

          <!-- Activity List -->
          <div *ngIf="recentLogins.length > 0" class="space-y-3.5">
            <div *ngFor="let login of recentLogins" class="flex justify-between items-center gap-2 border-b border-slate-50 dark:border-slate-800 pb-2.5 last:border-0 last:pb-0">
              <div class="flex items-center gap-2 overflow-hidden min-w-0">
                <span 
                  [ngClass]="login.exitoso ? 'text-emerald-500 dark:text-emerald-300 bg-emerald-50 dark:bg-emerald-950/30 border-emerald-100 dark:border-emerald-900/40' : 'text-red-500 dark:text-red-300 bg-red-50 dark:bg-red-950/30 border-red-100 dark:border-red-900/40'" 
                  class="material-symbols-outlined text-sm font-black p-1 border rounded-none shrink-0 select-none">
                  {{ login.exitoso ? 'check' : 'close' }}
                </span>
                <div class="overflow-hidden min-w-0">
                  <span class="font-bold text-xs text-slate-800 dark:text-slate-200 block truncate">{{ login.correo }}</span>
                  <span class="text-[9px] font-mono text-slate-400 dark:text-slate-500 block truncate">IP: {{ login.ip }} • {{ login.userAgent || 'Navegador desconocido' }}</span>
                </div>
              </div>
              <div class="text-right shrink-0">
                <span class="text-[9px] font-bold text-slate-500 dark:text-slate-400 block uppercase">{{ login.fecha | date:'dd/MM HH:mm' }}</span>
                <span *ngIf="!login.exitoso" class="text-[8px] bg-red-100 dark:bg-red-950/30 text-red-700 dark:text-red-200 px-1 py-0.2 rounded-none font-bold uppercase">{{ login.motivo || 'Fallo' }}</span>
              </div>
            </div>
          </div>
        </div>

      </div>

      <!-- Campus Content and Audit Logs Summary -->
      <div class="grid grid-cols-1 lg:grid-cols-2 gap-4 sm:gap-6 mt-4 sm:mt-6">

        <!-- Campus Courses list Widget -->
        <div class="border border-slate-200 dark:border-slate-800 p-4 sm:p-6 bg-white dark:bg-slate-900 rounded-none shadow-[4px_4px_0px_0px_rgba(15,23,42,0.05)] dark:shadow-[4px_4px_0px_0px_rgba(0,0,0,0.22)] transition-colors duration-300">
          <div class="flex items-center justify-between border-b border-slate-100 dark:border-slate-800 pb-3 mb-4">
            <h2 class="text-xs font-black text-slate-900 dark:text-slate-100 uppercase tracking-wider flex items-center gap-1.5">
              <span class="material-symbols-outlined text-base text-indigo-600 shrink-0">auto_stories</span>
              Cursos Registrados
            </h2>
            <a routerLink="/dashboard/cursos" class="text-[9px] font-bold text-indigo-600 hover:text-indigo-800 dark:text-indigo-400 dark:hover:text-indigo-300 uppercase tracking-widest shrink-0 ml-2">
              Administrar Todos
            </a>
          </div>

          <!-- Empty state -->
          <div *ngIf="coursesList.length === 0" class="text-center py-10 text-slate-400 dark:text-slate-500">
            <span class="material-symbols-outlined text-3xl mb-1 text-slate-300 dark:text-slate-600">folder_open</span>
            <p class="text-xs">No hay cursos registrados en el campus virtual.</p>
          </div>

          <!-- Courses list -->
          <div *ngIf="coursesList.length > 0" class="space-y-3">
            <div *ngFor="let c of coursesList" class="flex items-center justify-between gap-3 border-b border-slate-50 dark:border-slate-800 pb-3 last:border-0 last:pb-0">
              <div class="overflow-hidden min-w-0 flex-1">
                <div class="flex items-center gap-2 flex-wrap">
                  <span class="font-bold text-xs text-slate-800 dark:text-slate-200 block truncate">{{ c.nombre }}</span>
                  <span [ngClass]="c.estado ? 'bg-emerald-50 dark:bg-emerald-950/30 text-emerald-700 dark:text-emerald-200 border-emerald-100 dark:border-emerald-900/40' : 'bg-red-50 dark:bg-red-950/30 text-red-700 dark:text-red-200 border-red-100 dark:border-red-900/40'" class="border text-[8px] font-black uppercase px-1.5 py-0.2 shrink-0">
                    {{ c.estado ? 'Activo' : 'Inactivo' }}
                  </span>
                </div>
                <span class="text-[10px] text-slate-500 dark:text-slate-400 block truncate mt-0.5">{{ c.descripcion }}</span>
              </div>
              <a 
                [routerLink]="['/dashboard/cursos', c.id]"
                class="p-1 border border-slate-200 dark:border-slate-700 hover:border-slate-400 dark:hover:border-slate-500 text-slate-700 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors shrink-0">
                <span class="material-symbols-outlined text-sm block">edit</span>
              </a>
            </div>
          </div>
        </div>

        <!-- Recent Auditoria Events list Widget -->
        <div class="border border-slate-200 dark:border-slate-800 p-4 sm:p-6 bg-white dark:bg-slate-900 rounded-none shadow-[4px_4px_0px_0px_rgba(15,23,42,0.05)] dark:shadow-[4px_4px_0px_0px_rgba(0,0,0,0.22)] transition-colors duration-300">
          <div class="flex items-center justify-between border-b border-slate-100 dark:border-slate-800 pb-3 mb-4">
            <h2 class="text-xs font-black text-slate-900 dark:text-slate-100 uppercase tracking-wider flex items-center gap-1.5">
              <span class="material-symbols-outlined text-base text-indigo-600 shrink-0">history</span>
              Bitácora de Eventos
            </h2>
            <a routerLink="/dashboard/auditoria" class="text-[9px] font-bold text-indigo-600 hover:text-indigo-800 dark:text-indigo-400 dark:hover:text-indigo-300 uppercase tracking-widest shrink-0 ml-2">
              Ver Detalles
            </a>
          </div>

          <!-- Empty state -->
          <div *ngIf="recentEvents.length === 0" class="text-center py-10 text-slate-400 dark:text-slate-500">
            <span class="material-symbols-outlined text-3xl mb-1 text-slate-300 dark:text-slate-600">receipt_long</span>
            <p class="text-xs">No hay registros de eventos operativos en el sistema.</p>
          </div>

          <!-- Events list -->
          <div *ngIf="recentEvents.length > 0" class="space-y-3.5">
            <div *ngFor="let ev of recentEvents" class="flex justify-between items-center gap-2 border-b border-slate-50 dark:border-slate-800 pb-2.5 last:border-0 last:pb-0">
              <div class="flex items-start gap-2 overflow-hidden min-w-0 flex-1">
                <div class="text-[8px] font-black uppercase px-2 py-0.5 bg-slate-900 dark:bg-slate-800 text-slate-300 dark:text-slate-200 border border-slate-800 dark:border-slate-700 shrink-0 mt-0.5">
                  {{ ev.modulo }}
                </div>
                <div class="overflow-hidden min-w-0">
                  <span class="font-bold text-xs text-slate-800 dark:text-slate-200 block truncate">{{ ev.descripcion }}</span>
                  <span class="text-[9px] font-mono text-slate-400 dark:text-slate-500 block truncate">Operación: {{ ev.accion }}</span>
                </div>
              </div>
              <div class="text-right shrink-0">
                <span class="text-[9px] font-bold text-slate-500 dark:text-slate-400 block uppercase">{{ ev.fecha | date:'dd/MM HH:mm' }}</span>
              </div>
            </div>
          </div>
        </div>

      </div>
    </ng-container>

    <!-- ================= ALUMNO VIEW ================= -->
    <ng-container *ngIf="profile.rol === 'ALUMNO'">
      <!-- Premium Welcome Banner -->
      <div class="relative overflow-hidden bg-gradient-to-r from-slate-950 via-[#0d1527] to-slate-950 border border-slate-800 p-5 sm:p-8 rounded-none shadow-[6px_6px_0px_0px_rgba(99,102,241,0.1)] text-white">
        <!-- Abstract light graphic -->
        <div class="absolute -right-16 -top-16 w-48 h-48 bg-indigo-500/10 rounded-full blur-3xl pointer-events-none"></div>
        <div class="absolute -left-16 -bottom-16 w-48 h-48 bg-blue-500/10 rounded-full blur-3xl pointer-events-none"></div>

        <div class="flex flex-col md:flex-row md:items-center justify-between gap-4 relative z-10">
          <div class="flex items-center gap-3 sm:gap-4">
            <div class="w-12 h-12 sm:w-14 sm:h-14 bg-gradient-to-br from-indigo-500 to-blue-600 flex items-center justify-center rounded-none font-black text-xl sm:text-2xl shadow-[4px_4px_0px_0px_rgba(255,255,255,0.2)] shrink-0">
              {{ profile.nombres.charAt(0) }}
            </div>
            <div>
              <span class="text-[9px] font-black tracking-widest text-indigo-400 uppercase">Panel del Estudiante</span>
              <h1 class="text-lg sm:text-2xl font-black tracking-tight uppercase mt-0.5">¡Hola de nuevo, {{ profile.nombres }}!</h1>
              <p class="text-slate-400 text-[11px] sm:text-xs mt-1">Tu espacio académico personalizado. Sigue tu avance y descarga certificados.</p>
            </div>
          </div>
          <div class="flex items-center gap-2" *ngIf="profile.nivelSuscripcion">
            <span class="w-2.5 h-2.5 bg-emerald-500 rounded-none animate-pulse"></span>
            <span class="text-[9px] font-black text-slate-300 uppercase tracking-widest bg-slate-900 border border-slate-800 px-3 py-1.5">
              Plan: {{ profile.nivelSuscripcion }}
            </span>
          </div>
        </div>
      </div>

      <!-- Dashboard Metrics Grid -->
      <div class="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 gap-4 sm:gap-6 mt-4 sm:mt-6">
        <!-- Metric 1: Cursos Inscritos -->
        <div class="border border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900 p-4 sm:p-6 rounded-none shadow-sm hover:shadow-md hover:-translate-y-0.5 transition-all duration-300 flex items-center justify-between">
          <div>
            <span class="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest">Cursos Inscritos</span>
            <h3 class="text-3xl sm:text-4xl font-black text-slate-900 dark:text-white mt-2 tracking-tight">{{ studentCursosInscritos }}</h3>
            <p class="text-[10px] text-slate-500 dark:text-slate-400 font-semibold mt-1.5">Matrícula académica activa</p>
          </div>
          <div class="w-12 h-12 sm:w-14 sm:h-14 border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 flex items-center justify-center text-slate-500 dark:text-slate-400 rounded-none shrink-0">
            <span class="material-symbols-outlined text-2xl sm:text-3xl">auto_stories</span>
          </div>
        </div>

        <!-- Metric 2: Cursos Completados -->
        <div class="border border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900 p-4 sm:p-6 rounded-none shadow-sm hover:shadow-md hover:-translate-y-0.5 transition-all duration-300 flex items-center justify-between">
          <div>
            <span class="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest">Cursos Completados</span>
            <h3 class="text-3xl sm:text-4xl font-black text-slate-900 dark:text-white mt-2 tracking-tight">{{ studentCursosCompletados }}</h3>
            <p class="text-[10px] text-emerald-600 font-bold mt-1.5 flex items-center gap-1">
              <span class="w-1.5 h-1.5 bg-emerald-500 rounded-full"></span>
              Metas alcanzadas
            </p>
          </div>
          <div class="w-12 h-12 sm:w-14 sm:h-14 border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 flex items-center justify-center text-slate-500 dark:text-slate-400 rounded-none shrink-0">
            <span class="material-symbols-outlined text-2xl sm:text-3xl">task_alt</span>
          </div>
        </div>

        <!-- Metric 3: Certificados Habilitados -->
        <div class="border border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900 p-4 sm:p-6 rounded-none shadow-sm hover:shadow-md hover:-translate-y-0.5 transition-all duration-300 flex items-center justify-between sm:col-span-2 md:col-span-1">
          <div>
            <span class="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest">Certificados Logrados</span>
            <h3 class="text-3xl sm:text-4xl font-black text-slate-900 dark:text-white mt-2 tracking-tight">{{ studentCertificados }}</h3>
            <p class="text-[10px] text-slate-500 dark:text-slate-400 font-semibold mt-1.5">Descargables desde el panel</p>
          </div>
          <div class="w-12 h-12 sm:w-14 sm:h-14 border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 flex items-center justify-center text-slate-400 dark:text-slate-500 rounded-none shrink-0">
            <span class="material-symbols-outlined text-2xl sm:text-3xl text-amber-500">workspace_premium</span>
          </div>
        </div>
      </div>

      <!-- Split Layout: Enrolled Courses & Quick Guide -->
      <div class="grid grid-cols-1 lg:grid-cols-3 gap-4 sm:gap-6 mt-4 sm:mt-6">

        <!-- Left: Active Enrolled Courses (2/3 width) -->
        <div class="lg:col-span-2 border border-slate-200 dark:border-slate-800 p-4 sm:p-6 bg-white dark:bg-slate-900 rounded-none shadow-sm space-y-4">
          <div class="flex items-center justify-between border-b border-slate-100 dark:border-slate-800 pb-3 mb-4">
            <h2 class="text-xs font-black text-slate-900 dark:text-white uppercase tracking-wider flex items-center gap-1.5">
              <span class="material-symbols-outlined text-base text-indigo-600 shrink-0">bookmark</span>
              Tus Cursos en Curso
            </h2>
            <a routerLink="/dashboard/mis-cursos" class="text-[9px] font-bold text-indigo-600 hover:text-indigo-800 dark:text-indigo-400 dark:hover:text-indigo-300 uppercase tracking-widest shrink-0 ml-2">
              Ver Todos
            </a>
          </div>

          <!-- Empty state -->
          <div *ngIf="studentCursos.length === 0" class="text-center py-10 text-slate-400 border border-dashed border-slate-200 dark:border-slate-800 bg-slate-50/50 dark:bg-slate-800/20">
            <span class="material-symbols-outlined text-3xl text-slate-300 dark:text-slate-600 mb-2">menu_book</span>
            <p class="text-xs">No te has inscrito en ningún curso actualmente.</p>
            <p class="text-[9px] text-slate-400 dark:text-slate-500 mt-1">Ponte en contacto con el administrador para matricularte.</p>
          </div>

          <!-- Courses list -->
          <div *ngIf="studentCursos.length > 0" class="space-y-4">
            <div *ngFor="let c of studentCursos" class="border border-slate-200 dark:border-slate-800 p-3 sm:p-4 bg-slate-50/50 dark:bg-slate-800/30 flex flex-col gap-3">
              <div class="space-y-2 overflow-hidden">
                <div class="flex items-center gap-2 flex-wrap">
                  <span class="text-xs font-bold text-slate-900 dark:text-slate-200 truncate uppercase tracking-tight block">{{ c.nombre }}</span>
                  <span *ngIf="c.completado" class="bg-emerald-100 dark:bg-emerald-950 text-emerald-800 dark:text-emerald-300 text-[8px] font-black uppercase px-2 py-0.5 border border-emerald-300 dark:border-emerald-900 shrink-0">
                    Completado
                  </span>
                </div>

                <!-- Progress bar -->
                <div class="space-y-1">
                  <div class="flex justify-between text-[9px] text-slate-400 dark:text-slate-500 font-mono">
                    <span>Progreso de videos</span>
                    <span class="font-bold text-indigo-600 dark:text-indigo-400">{{ c.avancePorcentaje | number:'1.0-1' }}%</span>
                  </div>
                  <div class="w-full bg-slate-200 dark:bg-slate-800 h-1.5 rounded-none overflow-hidden">
                    <div class="bg-indigo-600 dark:bg-indigo-500 h-full transition-all duration-500" [style.width.%]="c.avancePorcentaje"></div>
                  </div>
                </div>
              </div>

              <!-- Quick Action -->
              <div class="flex items-center">
                <a 
                  [routerLink]="['/dashboard/cursos-play', c.id]"
                  class="w-full sm:w-auto px-4 py-2.5 bg-slate-900 dark:bg-slate-800 hover:bg-slate-800 dark:hover:bg-slate-700 text-white text-[10px] font-bold uppercase tracking-widest transition-colors rounded-none shadow-[2px_2px_0px_0px_rgba(0,0,0,0.1)] flex items-center justify-center gap-1.5 select-none">
                  <span class="material-symbols-outlined text-xs">play_circle</span>
                  <span>{{ c.completado ? 'Repasar' : 'Estudiar' }}</span>
                </a>
              </div>
            </div>
          </div>
        </div>

        <!-- Right: Guide / Next Steps (1/3 width) -->
        <div class="border border-slate-200 dark:border-slate-800 p-4 sm:p-6 bg-white dark:bg-slate-900 rounded-none shadow-sm space-y-4">
          <div class="border-b border-slate-100 dark:border-slate-800 pb-3 mb-4">
            <h2 class="text-xs font-black text-slate-900 dark:text-white uppercase tracking-wider flex items-center gap-1.5">
              <span class="material-symbols-outlined text-base text-indigo-600 dark:text-indigo-400">tungsten</span>
              Guía de Inicio Rápido
            </h2>
          </div>

          <div class="space-y-4 text-xs leading-relaxed text-slate-600 dark:text-slate-400">
            <div class="border-l-2 border-indigo-600 pl-3.5 space-y-1">
              <h4 class="font-bold text-slate-900 dark:text-slate-200 uppercase tracking-wide text-[11px]">1. Mis Cursos Activos</h4>
              <p class="text-slate-500 dark:text-slate-400 text-[11px]">Haz clic en <strong>Estudiar</strong> en cualquier curso de la lista para ir directamente al reproductor de clases, módulos y descargas.</p>
            </div>

            <div class="border-l-2 border-slate-300 dark:border-slate-800 pl-3.5 space-y-1">
              <h4 class="font-bold text-slate-900 dark:text-slate-200 uppercase tracking-wide text-[11px]">2. Progreso al 100%</h4>
              <p class="text-slate-500 dark:text-slate-400 text-[11px]">Al marcar todas las clases como vistas, tu curso se marcará como completado automáticamente.</p>
            </div>

            <div class="border-l-2 border-slate-300 dark:border-slate-800 pl-3.5 space-y-1">
              <h4 class="font-bold text-slate-900 dark:text-slate-200 uppercase tracking-wide text-[11px]">3. Generación de Diploma</h4>
              <p class="text-slate-500 dark:text-slate-400 text-[11px]">Una vez terminado, dirígete a <strong>Certificados</strong> en la barra lateral o en la pestaña del curso para descargar tu PDF oficial.</p>
            </div>
          </div>
        </div>

      </div>
    </ng-container>
  </div>
</div>
